```typescript
// dashboard/src/stores/websocket.ts
import { defineStore } from 'pinia'
import { ref, computed } from 'vue'

export const useWebSocketStore = defineStore('websocket', () => {
  const socket = ref<WebSocket | null>(null)
  const isConnected = ref(false)
  const reconnectAttempts = ref(0)
  const maxReconnectAttempts = 5

  // 连接状态
  const connectionStatus = computed(() => {
    if (isConnected.value) return 'connected'
    if (reconnectAttempts.value > 0) return 'reconnecting'
    return 'disconnected'
  })

  // 连接 WebSocket
  function connect() {
    const wsUrl = import.meta.env.VITE_WS_BASE_URL || 'ws://localhost:3000/api/ws'

    socket.value = new WebSocket(wsUrl)

    socket.value.onopen = () => {
      console.log('✅ WebSocket 已连接')
      isConnected.value = true
      reconnectAttempts.value = 0
    }

    socket.value.onmessage = (event) => {
      try {
        const { type, data } = JSON.parse(event.data)
        handleMessage(type, data)
      } catch (error) {
        console.error('解析消息失败:', error)
      }
    }

    socket.value.onclose = () => {
      console.log('🔴 WebSocket 已断开')
      isConnected.value = false

      // 自动重连
      if (reconnectAttempts.value < maxReconnectAttempts) {
        setTimeout(() => {
          reconnectAttempts.value++
          console.log(`🔄 尝试重连 (${reconnectAttempts.value}/${maxReconnectAttempts})`)
          connect()
        }, 1000 * reconnectAttempts.value)
      }
    }

    socket.value.onerror = (error) => {
      console.error('WebSocket 错误:', error)
    }
  }

  // 处理消息
  function handleMessage(type: string, data: any) {
    switch (type) {
      case 'iteration.status_changed':
        // 更新迭代状态
        break
      case 'agent.status_changed':
        // 更新 Agent 状态
        break
      case 'system.metrics':
        // 更新系统指标
        break
      case 'log.entry':
        // 添加日志
        break
    }
  }

  // 断开连接
  function disconnect() {
    if (socket.value) {
      socket.value.close()
      socket.value = null
      isConnected.value = false
    }
  }

  return {
    isConnected,
    connectionStatus,
    reconnectAttempts,
    connect,
    disconnect
  }
})
```

**验收标准**:
- ✅ WebSocket 自动重连
