1. **创建 Dashboard 集成模块**
```typescript
// src/dashboard/integration/iteration-publisher.ts

import { RealtimeService } from '../services/realtime.service'
import { IterationService } from '../services/iteration.service'

export class IterationPublisher {
  private iterationService: IterationService
  private realtimeService: RealtimeService

  constructor(iterationService: IterationService, realtimeService: RealtimeService) {
    this.iterationService = iterationService
    this.realtimeService = realtimeService
  }

  // 迭代开始
  async onIterationStart(iterationNumber: number, requirement: string) {
    const iteration = this.iterationService.create({
      iterationNumber,
      status: 'running',
      requirement,
      startedAt: new Date()
    })

    // 广播迭代开始
    this.realtimeService.broadcastIterationStatusChange({
      iterationId: iteration.id,
      iterationNumber,
      status: 'running',
      timestamp: new Date()
    })

    return iteration
  }

  // Agent 开始执行
  async onAgentStart(iterationId: number, agentName: string, task: string) {
    // 广播 Agent 状态
    this.realtimeService.broadcastAgentStatusChange({
      iterationId,
      agentName,
      agentType: agentName as any,
      status: 'running',
      progress: 0,
      currentTask: task,
      timestamp: new Date()
    })
  }

  // Agent 进度更新
  async onAgentProgress(iterationId: number, agentName: string, progress: number) {
    // 更新数据库
    const agentService = new (await import('../services/agent.service')).AgentService(/* db */)
    agentService.updateProgress(iterationId, agentName, progress, null)

    // 广播进度
    this.realtimeService.broadcastAgentProgress({
      iterationId,
      agentName,
      progress,
      timestamp: new Date()
    })
  }

  // Agent 完成
  async onAgentComplete(iterationId: number, agentName: string, result: any) {
    // 广播完成
    this.realtimeService.broadcastAgentStatusChange({
      iterationId,
      agentName,
      agentType: agentName as any,
      status: 'completed',
      progress: 100,
      result,
      timestamp: new Date()
    })
  }

  // 迭代完成
  async onIterationComplete(iterationId: number, status: 'success' | 'failed') {
    // 更新迭代状态
    const iteration = this.iterationService.update(iterationId, {
      status,
      completedAt: new Date()
    })

    // 广播完成
    this.realtimeService.broadcastIterationStatusChange({
      iterationId,
      iterationNumber: iteration!.iterationNumber,
      status,
      timestamp: new Date()
    })
  }

  // 推送日志
  async onLogEntry(level: string, message: string, agent?: string) {
    this.realtimeService.broadcastLogEntry({
      level,
      message,
      agent,
      timestamp: new Date()
    })
  }
}
```

2. **集成到 AutoIterationEngine**
```typescript
// src/auto-iteration.ts

import { IterationPublisher } from './dashboard/integration/iteration-publisher'
import { getServices } from './dashboard/server'

export class AutoIterationEngine {
  private publisher?: IterationPublisher

  async start() {
    // 如果启用了 Dashboard，初始化发布者
    if (config.enableDashboard) {
      const services = await getServices()
      this.publisher = new IterationPublisher(
        services.iterationService,
        services.realtimeService
      )
    }

    // 开始迭代
    await this.runIteration()
  }

  async runIteration() {
    // 通知迭代开始
    if (this.publisher) {
      await this.publisher.onIterationStart(this.count, this.requirement)
    }

    try {
      // 产品经理 Agent
      await this.runProductManager()

      // 架构师 Agent
      await this.runArchitect()

      // ... 其他 Agents ...

      // 迭代完成
      if (this.publisher) {
        await this.publisher.onIterationComplete(iterationId, 'success')
      }
    } catch (error) {
      if (this.publisher) {
        await this.publisher.onIterationComplete(iterationId, 'failed')
      }
    }
  }

  async runProductManager() {
    const agentName = 'product-manager'

    // 通知 Agent 开始
    if (this.publisher) {
      await this.publisher.onAgentStart(iterationId, agentName, 'Analyzing requirements')
    }

    // 执行 Agent
    const result = await this.pmAgent.analyzeRequirements()

    // 通知完成
    if (this.publisher) {
      await this.publisher.onAgentComplete(iterationId, agentName, result)
    }
  }
}
